export async function updateLeadDetails(leadId: string, data: any) {
  const user = await getUserSession()
  if (!user) throw new Error('Unauthorized')

  const supabase = await createClient()
  const { data: lead } = await supabase
    .from('Lead')
    .select('assignedCounselorId')
    .eq('id', leadId)
    .eq('companyId', user.companyId)
    .single()

  if (!lead) throw new Error('Lead not found')

  if (user.role === 'Counselor' && lead.assignedCounselorId !== user.id) {
    throw new Error('Unauthorized')
  }

  // Whitelist editable fields to prevent mass assignment vulnerability
  const ALLOWED_FIELDS = [
    'fullName',
    'phone',
    'email',
    'lastStudyLevel',
    'preferredStudyLevel',
    'preferredCountry',
    'preferredCourse',
    'preferredIntake',
    'englishTestStatus',
    'englishTestType',
    'englishTestScore',
    'sscGroup',
    'sscYear',
    'sscResult',
    'hscGroup',
    'hscYear',
    'hscResult',
    'bachelorsMajor',
    'bachelorsYear',
    'bachelorsCgpa',
    'mastersMajor',
    'mastersYear',
    'mastersCgpa',
    'workExperience',
    'source',
    'budget',
    'initialNote'
  ]

  const sanitizedData: Record<string, any> = {}
  for (const key of ALLOWED_FIELDS) {
    if (data && key in data) {
      sanitizedData[key] = data[key]
    }
  }

  const { error: updateError } = await supabase
    .from('Lead')
    .update(sanitizedData)
    .eq('id', leadId)

  if (updateError) throw new Error('Failed to update details: ' + updateError.message)

  revalidatePath(`/dashboard/leads/${leadId}`)
  return { success: true }
}

