'use client'

import { useState, useEffect } from 'react'
import { updateLeadStageAction } from '@/app/actions/leads'
import { StarRating } from '@/components/StarRating'
import { PipelineStage } from '@/app/actions/stages'
import Link from 'next/link'
import { ExternalLink, User } from 'lucide-react'

// Pre-defined column colors for stages
const STAGE_DOT_COLORS = [
  '#4855E4', '#12A8B5', '#8B5CF6', '#1FAE73', '#FF7A52', '#E5484D', '#8B5CF6', '#EAB308'
]

interface Lead {
  id: string
  fullName: string
  preferredCountry: string | null
  stage: string
  rating: string | null
  createdAt: string
  updatedAt: string
  assignedCounselorId: string | null
  assignedCounselor?: { fullName: string } | { fullName: string }[] | null
}

interface PipelineBoardClientProps {
  initialLeads: Lead[]
  stages: PipelineStage[]
}

export default function PipelineBoardClient({ initialLeads, stages }: PipelineBoardClientProps) {
  const [leads, setLeads] = useState<Lead[]>(initialLeads)
  const [draggedId, setDraggedId] = useState<string | null>(null)
  const [dragOverStage, setDragOverStage] = useState<string | null>(null)
  const [activeStageName, setActiveStageName] = useState<string>(stages.length > 0 ? stages[0].name : '')

  const handleDragStart = (e: React.DragEvent, leadId: string) => {
    e.dataTransfer.setData('text/plain', leadId)
    setDraggedId(leadId)
  }

  const handleDragEnd = () => {
    setDraggedId(null)
    setDragOverStage(null)
  }

  const handleDragOver = (e: React.DragEvent, stageName: string) => {
    e.preventDefault()
    if (dragOverStage !== stageName) {
      setDragOverStage(stageName)
    }
  }

  const handleDrop = async (e: React.DragEvent, targetStageName: string) => {
    e.preventDefault()
    const leadId = e.dataTransfer.getData('text/plain')
    setDragOverStage(null)
    setDraggedId(null)

    if (!leadId) return

    const leadToMove = leads.find(l => l.id === leadId)
    if (!leadToMove) return

    const oldStage = leadToMove.stage
    if (oldStage === targetStageName) return

    // Optimistic Update
    setLeads(prev => prev.map(l => l.id === leadId ? { ...l, stage: targetStageName, updatedAt: new Date().toISOString() } : l))

    try {
      const result = await updateLeadStageAction(leadId, targetStageName)
      if (!result.success) {
        throw new Error('Failed to update stage')
      }
    } catch (err) {
      console.error('Error shifting lead stage:', err)
      // Rollback on failure
      setLeads(prev => prev.map(l => l.id === leadId ? { ...l, stage: oldStage } : l))
    }
  }

  const getInitials = (name: string) => {
    return name
      .split(' ')
      .map(n => n[0])
      .slice(0, 2)
      .join('')
      .toUpperCase()
  }

  const getStageColor = (index: number) => {
    return STAGE_DOT_COLORS[index % STAGE_DOT_COLORS.length]
  }

  return (
    <div className="flex-1 flex flex-col gap-4 min-h-0 w-full">
      {/* Mobile stage selector tabs */}
      <div className="flex lg:hidden overflow-x-auto gap-2.5 pb-2.5 px-0.5 scrollbar-none shrink-0 w-full">
        {stages.map((stage) => {
          const count = leads.filter(l => l.stage === stage.name).length
          const isActive = activeStageName === stage.name
          return (
            <button
              key={stage.id}
              type="button"
              onClick={() => setActiveStageName(stage.name)}
              className={`px-4 py-2 text-[11px] font-bold rounded-xl whitespace-nowrap transition-all duration-150 shrink-0 border-none ${
                isActive
                  ? 'text-[#202638] bg-[#E7ECF3] shadow-[inset_2.5px_2.5px_5px_#AEB9C9,inset_-2.5px_-2.5px_5px_#FFFFFF]'
                  : 'text-[#5C6478] bg-[#E7ECF3] shadow-[3px_3px_6px_#AEB9C9,-3px_-3px_6px_#FFFFFF] hover:text-[#202638]'
              }`}
            >
              {stage.name} ({count})
            </button>
          )
        })}
      </div>

      <div className="w-full overflow-x-auto flex gap-4 pb-6 select-none items-start flex-1 min-h-0">
        {stages.map((stage, sIdx) => {
          const stageLeads = leads.filter(l => l.stage === stage.name)
          const isDraggingOverThis = dragOverStage === stage.name
          const dotColor = getStageColor(sIdx)
          const isMobileHidden = activeStageName && activeStageName !== stage.name

          return (
            <div
              key={stage.id}
              onDragOver={(e) => handleDragOver(e, stage.name)}
              onDragLeave={() => setDragOverStage(null)}
              onDrop={(e) => handleDrop(e, stage.name)}
              className={`min-w-[155px] max-w-[210px] bg-[#E7ECF3] rounded-xl flex flex-col max-h-[calc(100vh-230px)] transition-all duration-200 border-2 ${
                isMobileHidden ? 'hidden lg:flex' : 'flex'
              } ${
                isDraggingOverThis
                  ? 'border-[#4855E4]/40 bg-[#DCE3ED]/30 shadow-[inset_4px_4px_8px_#AEB9C9,inset_-4px_-4px_8px_#FFFFFF]'
                  : 'border-transparent shadow-[4px_4px_10px_#AEB9C9,-4px_-4px_10px_#FFFFFF]'
              }`}
            >
            {/* Column Header */}
            <div className="p-2.5 flex items-center justify-between border-b border-[#AEB9C9]/20 shrink-0">
              <div className="flex items-center gap-1.5 min-w-0">
                <span className="w-2 h-2 rounded-full shrink-0" style={{ backgroundColor: dotColor }}></span>
                <span className="text-[11px] font-bold text-[#202638] font-display truncate max-w-[95px]" title={stage.name}>
                  {stage.name}
                </span>
              </div>
              <span className="text-[9px] font-bold text-[#8891A3] bg-[#DCE3ED] px-1.5 py-0.5 rounded-full shadow-[inset_1px_1px_2px_#AEB9C9,inset_-1px_-1px_2px_#FFFFFF] shrink-0">
                {stageLeads.length}
              </span>
            </div>

            {/* Column Body Cards List */}
            <div className="flex-1 overflow-y-auto p-2 space-y-2.5 min-h-[100px] scrollbar-thin">
              {stageLeads.map((lead) => {
                const days = Math.max(0, Math.floor((Date.now() - new Date(lead.updatedAt || lead.createdAt).getTime()) / (1000 * 60 * 60 * 24)))
                const counselor = lead.assignedCounselor
                const counselorName = counselor 
                  ? (Array.isArray(counselor) ? counselor[0]?.fullName : counselor.fullName)
                  : undefined
                const isThisDragged = draggedId === lead.id

                return (
                  <div
                    key={lead.id}
                    draggable
                    onDragStart={(e) => handleDragStart(e, lead.id)}
                    onDragEnd={handleDragEnd}
                    className={`bg-[#E7ECF3] shadow-[3px_3px_6px_#AEB9C9,-3px_-3px_6px_#FFFFFF] rounded-xl p-2.5 cursor-grab active:cursor-grabbing hover:scale-102 hover:shadow-[4px_4px_8px_#AEB9C9,-4px_-4px_8px_#FFFFFF] transition-all duration-150 relative group border border-[#AEB9C9]/10 ${
                      isThisDragged ? 'opacity-30 scale-95 shadow-inner' : ''
                    }`}
                  >
                    {/* Top Row: Initials Badge & Name */}
                    <div className="flex items-start justify-between gap-1.5 mb-1.5">
                      <div className="flex items-center gap-1.5 min-w-0">
                        <div className="w-5.5 h-5.5 rounded-lg bg-gradient-to-br from-[#6E79F2] to-[#333FC2] text-white flex items-center justify-center text-[8px] font-bold shrink-0 shadow-sm">
                          {getInitials(lead.fullName)}
                        </div>
                        <span className="text-[10.5px] font-bold text-[#202638] truncate" title={lead.fullName}>
                          {lead.fullName}
                        </span>
                      </div>
                      
                      <Link 
                        href={`/dashboard/leads/${lead.id}`}
                        className="p-0.5 rounded text-[#8891A3] hover:text-[#4855E4] hover:bg-[#DCE3ED]/50 transition-colors shrink-0"
                        title="View profile"
                      >
                        <ExternalLink className="w-3 h-3" />
                      </Link>
                    </div>

                    {/* Middle Row: Preferences */}
                    <p className="text-[9px] font-semibold text-[#5C6478] mb-2 truncate">
                      {lead.preferredCountry ? `Pref: ${lead.preferredCountry}` : 'No destination'}
                    </p>

                    {/* Bottom Row: Ratings, Counselor & Days */}
                    <div className="flex items-center justify-between border-t border-[#AEB9C9]/10 pt-2 mt-1">
                      <div className="flex flex-col gap-0.5 min-w-0">
                        <StarRating rating={lead.rating} editable={false} size={8} />
                        <span className="text-[8px] font-semibold text-[#8891A3] truncate">
                          {days === 0 ? 'Today' : `${days}d in stage`}
                        </span>
                      </div>

                      {counselorName ? (
                        <div 
                          className="w-4.5 h-4.5 rounded-full bg-[#12A8B5] text-white flex items-center justify-center text-[7px] font-extrabold shadow-sm shrink-0"
                          title={`Assigned to ${counselorName}`}
                        >
                          {getInitials(counselorName)}
                        </div>
                      ) : (
                        <div 
                          className="w-4.5 h-4.5 rounded-full bg-[#C7CFDC]/50 text-[#8891A3] flex items-center justify-center shadow-inner shrink-0"
                          title="Unassigned counselor"
                        >
                          <User className="w-2.5 h-2.5" />
                        </div>
                      )}
                    </div>
                  </div>
                )
              })}

              {stageLeads.length === 0 && (
                <div className="h-16 border-2 border-dashed border-[#AEB9C9]/20 rounded-xl flex items-center justify-center text-[9px] font-bold text-[#8891A3]/80">
                  Drop leads
                </div>
              )}
            </div>
          </div>
        )
      })}
      </div>
    </div>
  )
}

'use client'

import { useState } from 'react'
import { createStaff, updateStaff, deleteStaff } from '@/app/actions/staff'
import { Plus, Edit2, Trash2, X } from 'lucide-react'

export default function StaffClient({ initialUsers }: { initialUsers: any[] }) {
  const [users, setUsers] = useState(initialUsers)
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [editingUser, setEditingUser] = useState<any>(null)
  const [formData, setFormData] = useState({ fullName: '', email: '', role: 'Counselor' })
  const [error, setError] = useState('')
  const [isLoading, setIsLoading] = useState(false)

  const openModal = (user?: any) => {
    setError('')
    if (user) {
      setEditingUser(user)
      setFormData({ fullName: user.fullName, email: user.email, role: user.role })
    } else {
      setEditingUser(null)
      setFormData({ fullName: '', email: '', role: 'Counselor' })
    }
    setIsModalOpen(true)
  }

  const closeModal = () => {
    setIsModalOpen(false)
    setEditingUser(null)
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setIsLoading(true)
    setError('')
    
    const data = new FormData()
    data.append('fullName', formData.fullName)
    data.append('email', formData.email)
    data.append('role', formData.role)

    let res
    if (editingUser) {
      res = await updateStaff(editingUser.id, data)
    } else {
      res = await createStaff(data)
    }

    if (res.error) {
      setError(res.error)
      setIsLoading(false)
    } else {
      window.location.reload()
    }
  }

  const handleDelete = async (id: string) => {
    if (!confirm('Are you sure you want to delete this user?')) return
    const res = await deleteStaff(id)
    if (res.error) {
      alert(res.error)
    } else {
      window.location.reload()
    }
  }

  const inputClass = "w-full bg-[#E7ECF3] shadow-[inset_2.5px_2.5px_5px_#AEB9C9,inset_-2.5px_-2.5px_5px_#FFFFFF] border-none rounded-xl py-2.5 px-3 text-xs font-semibold text-[#202638] placeholder-[#8891A3] focus:outline-none transition-all"
  const selectClass = "w-full bg-[#E7ECF3] shadow-[3px_3px_6px_#AEB9C9,-3px_-3px_6px_#FFFFFF] text-xs font-bold text-[#5C6478] rounded-xl py-2.5 px-3 outline-none focus:shadow-[inset_2px_2px_4px_#AEB9C9,inset_-2px_-2px_4px_#FFFFFF] transition-all cursor-pointer"

  return (
    <>
      <div className="space-y-8 pb-12">
        <div className="flex justify-between items-center">
          <div>
            <h2 className="text-2xl font-bold text-[#202638] font-display">Staff Management</h2>
            <p className="text-xs text-[#5C6478]">Manage counselor accounts, administrative permissions, and roles.</p>
          </div>
          <button 
            onClick={() => openModal()} 
            className="flex items-center gap-1.5 px-5 py-3 bg-gradient-to-br from-[#6E79F2] to-[#333FC2] text-white text-xs font-bold rounded-xl shadow-md hover:shadow-[9px_9px_20px_rgba(51,63,194,0.35)] active:translate-y-0.5 transition-all duration-150"
          >
            <Plus className="h-4.5 w-4.5" /> Add Staff
          </button>
        </div>

        {/* Staff Table Container */}
        <div className="neo-raised overflow-hidden">
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-[#AEB9C9]/20">
              <thead className="bg-[#DCE3ED]">
                <tr className="text-[#5C6478] text-[10px] font-bold uppercase tracking-wider">
                  <th className="px-6 py-4 text-left">Name</th>
                  <th className="px-6 py-4 text-left">Email</th>
                  <th className="px-6 py-4 text-left">Role</th>
                  <th className="px-6 py-4 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-[#AEB9C9]/20 bg-[#E7ECF3]">
                {users.map((user) => (
                  <tr key={user.id} className="hover:bg-[#DCE3ED]/25 transition-colors group">
                    <td className="px-6 py-4 whitespace-nowrap text-xs font-bold text-[#202638]">{user.fullName}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-xs font-semibold text-[#5C6478]">{user.email}</td>
                    <td className="px-6 py-4 whitespace-nowrap text-xs font-semibold">
                      <span className={`px-2.5 py-0.5 inline-flex text-[10px] font-bold leading-5 rounded-full border ${
                        user.role === 'Super Admin' 
                          ? 'bg-red-500/10 text-red-600 border-red-500/20' 
                          : user.role === 'Manager' 
                            ? 'bg-blue-500/10 text-blue-600 border-blue-500/20' 
                            : 'bg-emerald-500/10 text-emerald-600 border-emerald-500/20'
                      }`}>
                        {user.role}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-xs font-bold space-x-2">
                      <button 
                        onClick={() => openModal(user)} 
                        className="inline-flex p-2 rounded-xl bg-[#E7ECF3] shadow-[3px_3px_6px_#AEB9C9,-3px_-3px_6px_#FFFFFF] text-[#4855E4] hover:shadow-[inset_2px_2px_4px_#AEB9C9,inset_-2px_-2px_4px_#FFFFFF] transition-all"
                        aria-label="Edit staff member details"
                      >
                        <Edit2 className="h-3.5 w-3.5" />
                      </button>
                      <button 
                        onClick={() => handleDelete(user.id)} 
                        className="inline-flex p-2 rounded-xl bg-[#E7ECF3] shadow-[3px_3px_6px_#AEB9C9,-3px_-3px_6px_#FFFFFF] text-red-500 hover:shadow-[inset_2px_2px_4px_#AEB9C9,inset_-2px_-2px_4px_#FFFFFF] transition-all"
                        aria-label="Delete staff member"
                      >
                        <Trash2 className="h-3.5 w-3.5" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* Staff Editor Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/30 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="neo-raised-lg max-w-md w-full p-8 animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-base font-bold text-[#202638]">{editingUser ? 'Edit Staff Details' : 'Add New Counselor'}</h3>
              <button 
                onClick={closeModal} 
                className="p-1.5 rounded-xl bg-[#E7ECF3] shadow-[3px_3px_6px_#AEB9C9,-3px_-3px_6px_#FFFFFF] hover:shadow-[inset_2px_2px_4px_#AEB9C9,inset_-2px_-2px_4px_#FFFFFF] text-[#5C6478] transition-all"
                aria-label="Close editing details dialog"
              >
                <X className="h-4 w-4" />
              </button>
            </div>
            
            {error && (
              <div className="mb-4 p-3 bg-red-500/10 border border-red-500/20 text-red-600 text-xs font-bold rounded-xl shadow-sm">
                {error}
              </div>
            )}
            
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-[#5C6478] mb-2">Full Name</label>
                <input required type="text" value={formData.fullName} onChange={e => setFormData({...formData, fullName: e.target.value})} className={inputClass} placeholder="E.g. Tanvir Ahmed" />
              </div>
              <div>
                <label className="block text-xs font-bold text-[#5C6478] mb-2">Email</label>
                <input required type="email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className={inputClass} placeholder="tanvir@agency.com" />
              </div>
              <div>
                <label className="block text-xs font-bold text-[#5C6478] mb-2">Role</label>
                <select value={formData.role} onChange={e => setFormData({...formData, role: e.target.value})} className={selectClass}>
                  <option value="Counselor">Counselor</option>
                  <option value="Manager">Manager</option>
                  <option value="Super Admin">Super Admin</option>
                </select>
              </div>
              
              <div className="pt-4 flex justify-end gap-3">
                <button 
                  type="button" 
                  onClick={closeModal} 
                  className="px-5 py-2.5 rounded-xl bg-[#E7ECF3] shadow-[3px_3px_6px_#AEB9C9,-3px_-3px_6px_#FFFFFF] text-xs font-bold text-[#5C6478] hover:shadow-[inset_2px_2px_4px_#AEB9C9,inset_-2px_-2px_4px_#FFFFFF] transition-all"
                >
                  Cancel
                </button>
                <button 
                  type="submit" 
                  disabled={isLoading} 
                  className="px-5 py-2.5 rounded-xl bg-gradient-to-br from-[#6E79F2] to-[#333FC2] text-white text-xs font-bold shadow-md hover:shadow-lg disabled:opacity-50 transition-all"
                >
                  {isLoading ? 'Saving...' : 'Save'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </>
  )
}

'use client'

import { useState, useEffect } from 'react'
import useSWR from 'swr'
import { createPortal } from 'react-dom'
import { createClient } from '@/utils/supabase/client'
import { createTask, updateTaskStatus, deleteTask } from '@/app/actions/tasks'
import { CheckSquare, Clock, Plus, Trash2, X, AlertTriangle, Calendar, User, Loader2 } from 'lucide-react'
import Link from 'next/link'

// SWR Tasks Fetcher
const tasksFetcher = async () => {
  const supabase = createClient()

  const { data: { session } } = await supabase.auth.getSession()
  if (!session) return []

  const { data: user } = await supabase
    .from('User')
    .select('id, role, companyId')
    .eq('id', session.user.id)
    .single()

  if (!user) return []

  const isAdminOrManager = user.role === 'Super Admin' || user.role === 'Manager'

  let query = supabase
    .from('Task')
    .select('*, counselor:User!inner(fullName, role, companyId), lead:Lead(id, fullName)')
    .order('dueDate', { ascending: true })

  if (!isAdminOrManager) {
    query = query.eq('counselorId', user.id)
  } else {
    query = query.eq('counselor.companyId', user.companyId)
  }

  const { data, error } = await query
  if (error) {
    console.error('SWR Tasks Fetch Error:', error)
    return []
  }
  return data || []
}

export default function TasksClient({ 
  tasks, 
  counselors, 
  isAdminOrManager, 
  currentUser 
}: { 
  tasks: any[]
  counselors: any[]
  isAdminOrManager: boolean
  currentUser: any 
}) {
  const [mounted, setMounted] = useState(false)
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [formData, setFormData] = useState({ 
    description: '', 
    dueDate: '', 
    counselorId: counselors.length > 0 ? counselors[0].id : currentUser.id 
  })
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [errorMsg, setErrorMsg] = useState('')

  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setMounted(true)
  }, [])

  // SWR Caching
  const { data: clientTasks, mutate } = useSWR(
    'tasks',
    tasksFetcher,
    {
      fallbackData: tasks,
      revalidateOnFocus: false,
      revalidateOnReconnect: true,
      dedupingInterval: 5000
    }
  )

  const activeTasks = clientTasks || tasks

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setIsSubmitting(true)
    setErrorMsg('')
    
    const data = new FormData()
    data.append('description', formData.description)
    data.append('dueDate', formData.dueDate)
    data.append('counselorId', formData.counselorId)

    try {
      const res = await createTask(data)
      if (res && 'error' in res) {
        setErrorMsg(res.error || 'Failed to create task')
      } else {
        mutate() // trigger revalidation
        setFormData({ 
          description: '', 
          dueDate: '', 
          counselorId: counselors.length > 0 ? counselors[0].id : currentUser.id 
        })
        setIsModalOpen(false)
      }
    } catch (err: any) {
      setErrorMsg(err.message || 'Failed to create task')
    } finally {
      setIsSubmitting(false)
    }
  }

  const handleStatusChange = async (taskId: string, currentStatus: string) => {
    const newStatus = currentStatus === 'Pending' ? 'Completed' : 'Pending'
    
    // Optimistic cache update
    mutate(
      activeTasks.map(t => t.id === taskId ? { ...t, status: newStatus } : t),
      false
    )

    try {
      await updateTaskStatus(taskId, newStatus)
      mutate()
    } catch (err) {
      mutate() // rollback
    }
  }

  const handleDelete = async (taskId: string) => {
    if (!confirm('Are you sure you want to delete this task?')) return
    
    // Optimistic delete
    mutate(
      activeTasks.filter(t => t.id !== taskId),
      false
    )

    try {
      await deleteTask(taskId)
      mutate()
    } catch (err) {
      mutate()
    }
  }

  const getInitials = (name: string) => {
    return name
      .split(' ')
      .map(n => n[0])
      .slice(0, 2)
      .join('')
      .toUpperCase()
  }

  // Group tasks by urgency/date
  const now = new Date()
  const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate())
  const tomorrowStart = new Date(todayStart.getTime() + 24 * 60 * 60 * 1000)

  const overdueTasks: any[] = []
  const todayTasks: any[] = []
  const upcomingTasks: any[] = []
  const completedTasks: any[] = []

  activeTasks.forEach(task => {
    if (task.status === 'Completed') {
      completedTasks.push(task)
      return
    }

    const due = new Date(task.dueDate)
    const dueDay = new Date(due.getFullYear(), due.getMonth(), due.getDate())

    if (dueDay < todayStart) {
      overdueTasks.push(task)
    } else if (dueDay.getTime() === todayStart.getTime()) {
      todayTasks.push(task)
    } else {
      upcomingTasks.push(task)
    }
  })

  const inputClass = "w-full bg-[#E7ECF3] shadow-[inset_2.5px_2.5px_5px_#AEB9C9,inset_-2.5px_-2.5px_5px_#FFFFFF] border-none rounded-xl py-2.5 px-4 text-xs font-semibold text-[#202638] placeholder-[#8891A3] focus:outline-none transition-all"
  const selectClass = "w-full bg-[#E7ECF3] shadow-[3px_3px_6px_#AEB9C9,-3px_-3px_6px_#FFFFFF] text-xs font-bold text-[#5C6478] rounded-xl py-2.5 px-4 outline-none focus:shadow-[inset_2px_2px_4px_#AEB9C9,inset_-2px_-2px_4px_#FFFFFF] transition-all cursor-pointer"

  const renderTaskRow = (task: any) => {
    const isCompleted = task.status === 'Completed'
    const due = new Date(task.dueDate)
    const formattedTime = due.toLocaleString([], { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' })
    const counselorName = task.counselor?.fullName

    return (
      <div 
        key={task.id} 
        className={`flex items-center gap-4 p-4 mb-3.5 bg-[#E7ECF3] rounded-2xl shadow-[4px_4px_8px_#AEB9C9,-4px_-4px_8px_#FFFFFF] border border-[#AEB9C9]/10 group transition-all duration-300 ${
          isCompleted ? 'opacity-60' : ''
        }`}
      >
        {/* check-circle checkbox */}
        <button
          type="button"
          onClick={() => handleStatusChange(task.id, task.status)}
          disabled={!isAdminOrManager && currentUser.id !== task.counselorId}
          className={`w-6 h-6 rounded-full flex items-center justify-center shrink-0 cursor-pointer border-none transition-all duration-200 ${
            isCompleted 
              ? 'bg-gradient-to-br from-[#1FAE73] to-[#158a5c] shadow-[2px_2px_6px_rgba(21,138,92,0.4)] text-white'
              : 'bg-[#E7ECF3] shadow-[inset_2.5px_2.5px_5px_#AEB9C9,inset_-2.5px_-2.5px_5px_#FFFFFF] text-transparent hover:text-[#8891A3]'
          }`}
          aria-label={isCompleted ? "Mark task as pending" : "Mark task as completed"}
        >
          <CheckSquare className="w-3.5 h-3.5 stroke-[3]" />
        </button>

        {/* Task Details */}
        <div className="flex-1 min-w-0">
          <p className={`text-xs font-bold text-[#202638] mb-1 leading-normal ${isCompleted ? 'line-through text-[#8891A3]' : ''}`}>
            {task.description}
          </p>
          <div className="flex flex-wrap items-center gap-2.5 text-[10px] text-[#5C6478] font-semibold">
            {task.lead && (
              <span className="bg-[#4855E4]/8 text-[#333FC2] px-2.5 py-0.5 rounded-full font-bold">
                <Link href={`/dashboard/leads/${task.lead.id}`} className="hover:underline">
                  {task.lead.fullName}
                </Link>
              </span>
            )}
            <span className="flex items-center gap-1 text-[#8891A3]">
              <Clock className="w-3.5 h-3.5" />
              {formattedTime}
            </span>
          </div>
        </div>

        {/* Counselor Badge */}
        {counselorName && (
          <div 
            className="w-6.5 h-6.5 rounded-lg bg-gradient-to-br from-[#6E79F2] to-[#333FC2] text-white flex items-center justify-center text-[8.5px] font-bold shadow-sm shrink-0"
            title={`Assigned to ${counselorName}`}
          >
            {getInitials(counselorName)}
          </div>
        )}

        {/* Action Trash button */}
        {isAdminOrManager && (
          <button
            onClick={() => handleDelete(task.id)}
            className="text-[#8891A3] hover:text-[#E5484D] transition-colors shrink-0 p-1.5 rounded-lg opacity-0 group-hover:opacity-100 focus:opacity-100"
            aria-label="Delete task"
          >
            <Trash2 className="w-4 h-4" />
          </button>
        )}
      </div>
    )
  }

  return (
    <div className="max-w-4xl mx-auto space-y-8 pb-12">
      
      {/* Header controls */}
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-[#202638] font-display">Tasks</h2>
          <p className="text-xs text-[#5C6478]">Your team's follow-up agenda, organized by urgency.</p>
        </div>
        {isAdminOrManager && (
          <button 
            onClick={() => {
              setErrorMsg('')
              setIsModalOpen(true)
            }}
            className="flex items-center gap-1.5 px-5 py-3 bg-gradient-to-br from-[#6E79F2] to-[#333FC2] text-white text-xs font-bold rounded-xl shadow-md hover:shadow-[9px_9px_20px_rgba(51,63,194,0.35)] active:translate-y-0.5 transition-all duration-150"
          >
            <Plus className="h-4.5 w-4.5" />
            New Task
          </button>
        )}
      </div>

      {/* Main groupings */}
      <div className="space-y-8">
        
        {/* 1. Overdue Section */}
        {overdueTasks.length > 0 && (
          <div className="space-y-3">
            <div className="flex items-center gap-2 text-xs font-bold text-[#E5484D] px-1">
              <span className="w-2 h-2 rounded-full bg-[#E5484D]"></span>
              <span>Overdue</span>
              <span className="text-[10px] bg-[#E5484D]/10 px-2 py-0.5 rounded-full">{overdueTasks.length}</span>
            </div>
            <div>{overdueTasks.map(renderTaskRow)}</div>
          </div>
        )}

        {/* 2. Today Section */}
        <div className="space-y-3">
          <div className="flex items-center gap-2 text-xs font-bold text-[#4855E4] px-1">
            <span className="w-2 h-2 rounded-full bg-[#4855E4]"></span>
            <span>Today</span>
            <span className="text-[10px] bg-[#4855E4]/10 px-2 py-0.5 rounded-full">{todayTasks.length}</span>
          </div>
          {todayTasks.length === 0 ? (
            <div className="neo-raised p-6 text-center text-xs font-bold text-[#8891A3]">
              No tasks scheduled for today.
            </div>
          ) : (
            <div>{todayTasks.map(renderTaskRow)}</div>
          )}
        </div>

        {/* 3. Upcoming Section */}
        {upcomingTasks.length > 0 && (
          <div className="space-y-3">
            <div className="flex items-center gap-2 text-xs font-bold text-[#12A8B5] px-1">
              <span className="w-2 h-2 rounded-full bg-[#12A8B5]"></span>
              <span>Upcoming</span>
              <span className="text-[10px] bg-[#12A8B5]/10 px-2 py-0.5 rounded-full">{upcomingTasks.length}</span>
            </div>
            <div>{upcomingTasks.map(renderTaskRow)}</div>
          </div>
        )}

        {/* 4. Completed Section */}
        {completedTasks.length > 0 && (
          <div className="space-y-3">
            <div className="flex items-center gap-2 text-xs font-bold text-[#1FAE73] px-1">
              <span className="w-2 h-2 rounded-full bg-[#1FAE73]"></span>
              <span>Completed</span>
              <span className="text-[10px] bg-[#1FAE73]/10 px-2 py-0.5 rounded-full">{completedTasks.length}</span>
            </div>
            <div>{completedTasks.map(renderTaskRow)}</div>
          </div>
        )}

        {activeTasks.length === 0 && (
          <div className="neo-raised p-12 text-center text-xs font-bold text-[#8891A3]">
            No tasks found. Create a task to get started!
          </div>
        )}
      </div>

      {/* Creation Modal (Portaled) */}
      {mounted && isModalOpen && createPortal(
        <div className="fixed inset-0 bg-[#202638]/40 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
          <div className="relative z-10 max-w-md w-full bg-[#E7ECF3] shadow-[0_12px_36px_rgba(32,38,56,0.15)] border border-[#AEB9C9]/20 rounded-2xl p-6 md:p-8 space-y-6 animate-in fade-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center">
              <h3 className="text-base font-bold text-[#202638] font-display">Assign Task</h3>
              <button 
                onClick={() => setIsModalOpen(false)} 
                className="p-1.5 rounded-xl bg-[#E7ECF3] shadow-[3px_3px_6px_#AEB9C9,-3px_-3px_6px_#FFFFFF] hover:shadow-[inset_2px_2px_4px_#AEB9C9,inset_-2px_-2px_4px_#FFFFFF] text-[#5C6478] transition-all"
                aria-label="Close task creation panel"
              >
                <X className="h-4 w-4" />
              </button>
            </div>
            
            {errorMsg && (
              <div className="flex items-center gap-2 text-xs text-[#E5484D] bg-[#E5484D]/8 p-4 rounded-xl border border-[#E5484D]/10">
                <AlertTriangle className="w-4 h-4 shrink-0" />
                <span>{errorMsg}</span>
              </div>
            )}

            <form onSubmit={handleSubmit} className="space-y-5">
              <div>
                <label className="block text-[10px] font-bold text-[#5C6478] uppercase tracking-wider mb-2">Description</label>
                <input 
                  required 
                  type="text" 
                  value={formData.description} 
                  onChange={e => setFormData({...formData, description: e.target.value})} 
                  className={inputClass}
                  placeholder="e.g. Call Nusrat regarding visa documents" 
                />
              </div>
              
              <div>
                <label className="block text-[10px] font-bold text-[#5C6478] uppercase tracking-wider mb-2">Due Date</label>
                <input 
                  required 
                  type="datetime-local" 
                  value={formData.dueDate} 
                  onChange={e => setFormData({...formData, dueDate: e.target.value})} 
                  className={inputClass}
                />
              </div>

              <div>
                <label className="block text-[10px] font-bold text-[#5C6478] uppercase tracking-wider mb-2">Assign To</label>
                <select 
                  value={formData.counselorId} 
                  onChange={e => setFormData({...formData, counselorId: e.target.value})} 
                  className={selectClass}
                >
                  {counselors.map(c => (
                    <option key={c.id} value={c.id}>{c.fullName}</option>
                  ))}
                </select>
              </div>
              
              <div className="pt-2 flex justify-end gap-3">
                <button 
                  type="button" 
                  onClick={() => setIsModalOpen(false)} 
                  className="px-5 py-2.5 rounded-xl bg-[#E7ECF3] shadow-[3px_3px_6px_#AEB9C9,-3px_-3px_6px_#FFFFFF] text-xs font-bold text-[#5C6478] hover:shadow-[inset_2px_2px_4px_#AEB9C9,inset_-2px_-2px_4px_#FFFFFF] transition-all"
                >
                  Cancel
                </button>
                <button 
                  type="submit" 
                  disabled={isSubmitting} 
                  className="px-5 py-2.5 bg-gradient-to-br from-[#6E79F2] to-[#333FC2] text-white text-xs font-bold rounded-xl shadow-md hover:shadow-lg disabled:opacity-50 transition-all flex items-center gap-1.5"
                >
                  {isSubmitting && <Loader2 className="w-3.5 h-3.5 animate-spin" />}
                  <span>Assign</span>
                </button>
              </div>
            </form>
          </div>
        </div>,
        document.body
      )}
    </div>
  )
}

import { getUserSession } from '@/lib/auth'
import { createClient } from '@/utils/supabase/server'
import TasksClient from './TasksClient'
import { redirect } from 'next/navigation'

export default async function TasksPage() {
  const user = await getUserSession()
  if (!user) {
    redirect('/login')
  }

  const isAdminOrManager = user.role === 'Super Admin' || user.role === 'Manager'
  const supabase = await createClient()

  // Fetch counselors for the assignment dropdown (only if admin/manager)
  let counselors: any[] = []
  if (isAdminOrManager) {
    const { data: counselorsData } = await supabase
      .from('User')
      .select('id, fullName, role')
      .eq('role', 'Counselor')
      .eq('companyId', user.companyId)
    counselors = counselorsData || []
  } else {
    // A counselor can assign generic tasks to themselves (or it defaults to them)
    counselors = [{ id: user.id, fullName: user.fullName, role: user.role }]
  }

  // Fetch tasks
  // Admins/Managers see all tasks for the company. Counselors see only their assigned tasks.
  let tasksQuery = supabase
    .from('Task')
    .select('*, counselor:User!inner(fullName, role, companyId), lead:Lead(id, fullName)')
    .order('status', { ascending: false }) // 'Pending' (P) comes before 'Completed' (C) lexicographically when descending
    .order('dueDate', { ascending: true })

  if (!isAdminOrManager) {
    tasksQuery = tasksQuery.eq('counselorId', user.id)
  } else {
    tasksQuery = tasksQuery.eq('counselor.companyId', user.companyId)
  }

  const { data: tasksData } = await tasksQuery
  const tasks = tasksData || []

  return (
    <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 ease-out">
      <TasksClient 
        tasks={tasks} 
        counselors={counselors} 
        isAdminOrManager={isAdminOrManager} 
        currentUser={user} 
      />
    </div>
  )
}

