                <div className="mb-5 bg-[#E7ECF3] shadow-[inset_3px_3px_6px_#AEB9C9,inset_-3px_-3px_6px_#FFFFFF] p-4 rounded-xl space-y-4">
                  <input 
                    value={taskDescription}
                    onChange={e => setTaskDescription(e.target.value)}
