      </div>
      
      {/* Applications list */}
      <div className="neo-raised p-6">
        <div className="flex items-center justify-between mb-5">
          <h3 className="text-base font-bold text-[#202638] flex items-center gap-2">
            <Building className="h-5 w-5 text-[#12A8B5]" /> Applications
