                      </span>
                    )}
                  </div>
                  <div>
                    <h4 className="text-xs font-bold text-[#202638] mb-1 font-display">{app.university}</h4>
                    <p className="text-[11px] text-[#5C6478] font-semibold">{app.courseName}</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

'use client'

import { Search, Filter, Users } from 'lucide-react'
import { useRouter, useSearchParams, usePathname } from 'next/navigation'
import { useTransition } from 'react'
import { LEAD_STAGES, LEAD_RATINGS } from '@/lib/constants'
import { COUNTRIES } from '@/lib/countries'

type Counselor = { id: string; fullName: string }

export function LeadFilters({ 
  isAdminOrManager, 
  counselors, 
  sources = [],
  stages = []
}: { 
  isAdminOrManager: boolean
  counselors: Counselor[]
  sources?: string[] 
  stages?: any[]
}) {
  const router = useRouter()
  const pathname = usePathname()
  const searchParams = useSearchParams()
  const [isPending, startTransition] = useTransition()

  const handleSearch = (e: React.ChangeEvent<HTMLInputElement>) => {
    const term = e.target.value
    const params = new URLSearchParams(searchParams.toString())
    if (term) {
      params.set('q', term)
    } else {
      params.delete('q')
    }
    
    startTransition(() => {
      router.replace(`${pathname}?${params.toString()}`)
    })
  }

  const handleStageFilter = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const stage = e.target.value
    const params = new URLSearchParams(searchParams.toString())
    if (stage) {
      params.set('stage', stage)
    } else {
      params.delete('stage')
    }
    
    startTransition(() => {
      router.replace(`${pathname}?${params.toString()}`)
    })
  }

  const handleCounselorFilter = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const counselorId = e.target.value
    const params = new URLSearchParams(searchParams.toString())
    if (counselorId) {
      params.set('counselorId', counselorId)
    } else {
      params.delete('counselorId')
    }
    
    startTransition(() => {
      router.replace(`${pathname}?${params.toString()}`)
    })
  }

  const selectClass = "px-3 py-2 bg-[#E7ECF3] shadow-[3px_3px_6px_#AEB9C9,-3px_-3px_6px_#FFFFFF] text-xs font-bold text-[#5C6478] hover:text-[#202638] rounded-xl outline-none focus:shadow-[inset_2px_2px_4px_#AEB9C9,inset_-2px_-2px_4px_#FFFFFF] transition-all cursor-pointer"

  return (
    <div className="neo-raised p-6 flex flex-col gap-4 relative">
      {isPending && (
        <span className="absolute top-3 right-4 text-[10px] font-bold text-[#12A8B5] bg-[#12A8B5]/10 px-2 py-0.5 rounded-full">
          Updating...
        </span>
      )}
      
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4">
        {/* Search Input */}
        <div className="relative w-full lg:w-80">
          <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 h-4 w-4 text-[#8891A3]" />
          <input
            type="text"
            placeholder="Search by name, email, or phone..."
            defaultValue={searchParams.get('q') || ''}
            onChange={handleSearch}
            className="w-full pl-10 pr-4 py-3 bg-[#E7ECF3] shadow-[inset_3px_3px_6px_#AEB9C9,inset_-3px_-3px_6px_#FFFFFF] rounded-xl text-xs font-semibold text-[#202638] placeholder-[#8891A3] focus:outline-none focus:shadow-[inset_4px_4px_8px_#AEB9C9,inset_-4px_-4px_8px_#FFFFFF] transition-all"
          />
        </div>

        {/* Filters Controls */}
        <div className="flex flex-wrap items-center gap-3">
          {isAdminOrManager && (
            <div className="flex items-center gap-2">
              <Users className="h-4 w-4 text-[#8891A3] shrink-0" />
              <select 
                onChange={handleCounselorFilter}
                defaultValue={searchParams.get('counselorId') || ''}
                className={selectClass}
              >
                <option value="">All Counselors</option>
                {counselors.map(c => (
                  <option key={c.id} value={c.id}>{c.fullName}</option>
                ))}
              </select>
            </div>
          )}

          <div className="flex items-center gap-2">
            <Filter className="h-4 w-4 text-[#8891A3] shrink-0" />
            <select 
              onChange={handleStageFilter}
              defaultValue={searchParams.get('stage') || ''}
              className={selectClass}
            >
              <option value="">All Stages</option>
              {stages.length > 0 ? (
                stages.map(s => (
                  <option key={s.id} value={s.name}>{s.name}</option>
                ))
              ) : (
                LEAD_STAGES.map(stage => (
                  <option key={stage} value={stage}>{stage}</option>
                ))
              )}
            </select>
          </div>

          <select 
            onChange={(e) => {
              const rating = e.target.value
              const params = new URLSearchParams(searchParams.toString())
              if (rating) {
                params.set('rating', rating)
              } else {
                params.delete('rating')
              }
              startTransition(() => {
                router.replace(`${pathname}?${params.toString()}`)
              })
            }}
            defaultValue={searchParams.get('rating') || ''}
            className={selectClass}
          >
            <option value="">All Ratings</option>
            <option value="5">⭐⭐⭐⭐⭐ (5 Stars)</option>
            <option value="4">⭐⭐⭐⭐ (4 Stars)</option>
            <option value="3">⭐⭐⭐ (3 Stars)</option>
            <option value="2">⭐⭐ (2 Stars)</option>
            <option value="1">⭐ (1 Star)</option>
          </select>

          <select 
            onChange={(e) => {
              const country = e.target.value
              const params = new URLSearchParams(searchParams.toString())
              if (country) {
                params.set('country', country)
              } else {
                params.delete('country')
              }
              startTransition(() => {
                router.replace(`${pathname}?${params.toString()}`)
              })
            }}
            defaultValue={searchParams.get('country') || ''}
            className={`${selectClass} max-w-[150px] truncate`}
          >
            <option value="">All Countries</option>
            {COUNTRIES.map(c => (
              <option key={c} value={c}>{c}</option>
            ))}
          </select>

          <select 
            onChange={(e) => {
              const test = e.target.value
              const params = new URLSearchParams(searchParams.toString())
              if (test) {
                params.set('englishTest', test)
              } else {
                params.delete('englishTest')
              }
              startTransition(() => {
                router.replace(`${pathname}?${params.toString()}`)
              })
            }}
            defaultValue={searchParams.get('englishTest') || ''}
            className={selectClass}
          >
            <option value="">All English Tests</option>
            <option value="IELTS">IELTS</option>
            <option value="PTE">PTE</option>
            <option value="TOEFL">TOEFL</option>
            <option value="Duolingo">Duolingo</option>
            <option value="Other">Other</option>
          </select>

          <select 
            onChange={(e) => {
              const source = e.target.value
              const params = new URLSearchParams(searchParams.toString())
              if (source) {
                params.set('source', source)
              } else {
                params.delete('source')
              }
              startTransition(() => {
                router.replace(`${pathname}?${params.toString()}`)
              })
            }}
            defaultValue={searchParams.get('source') || ''}
            className={selectClass}
          >
            <option value="">All Sources</option>
            {sources.map(s => (
              <option key={s} value={s}>{s}</option>
            ))}
          </select>
        </div>
      </div>
    </div>
  )
}

'use client'

import { useState, useEffect } from 'react'
import { updateLeadStatus } from '@/app/actions/leads'
import { LEAD_STAGES } from '@/lib/constants'
import { StarRating } from './StarRating'

export function LeadStatusDropdowns({ 
  leadId, 
  currentStage, 
  currentRating,
  canEdit = true,
  stages = []
}: { 
  leadId: string, 
  currentStage: string, 
  currentRating: string | null,
  canEdit?: boolean
  stages?: any[]
}) {
  const [isPending, setIsPending] = useState(false)
  const [localStage, setLocalStage] = useState(currentStage)
  const [localRating, setLocalRating] = useState(currentRating || 'Unrated')

  // Keep state synced with parent props
  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setLocalStage(currentStage)
  }, [currentStage])

  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setLocalRating(currentRating || 'Unrated')
  }, [currentRating])

  const handleStageChange = async (e: React.ChangeEvent<HTMLSelectElement>) => {
    if (!canEdit) return
    const newStage = e.target.value
    const rollbackStage = localStage
    
    // Optimistic update
    setLocalStage(newStage)
    setIsPending(true)
    
    try {
      await updateLeadStatus(leadId, newStage, localRating)
    } catch (err) {
      setLocalStage(rollbackStage) // Rollback on error
    } finally {
      setIsPending(false)
    }
  }

  const handleRatingSelect = async (newRating: string) => {
    if (!canEdit) return
    const rollbackRating = localRating
    
    // Optimistic update
    setLocalRating(newRating)
    setIsPending(true)
    
    try {
      await updateLeadStatus(leadId, localStage, newRating)
    } catch (err) {
      setLocalRating(rollbackRating) // Rollback on error
    } finally {
      setIsPending(false)
    }
  }

  const selectClass = "bg-[#E7ECF3] text-xs font-bold text-[#202638] rounded-xl outline-none focus:shadow-[inset_2px_2px_4px_#AEB9C9,inset_-2px_-2px_4px_#FFFFFF] transition-all cursor-pointer h-[26px] border-none pr-2 bg-transparent"

  return (
    <div className="flex flex-wrap items-center gap-3 w-full md:w-auto">
      {isPending && <span className="text-[10px] font-bold text-[#8891A3] animate-pulse shrink-0">Saving...</span>}
      
      {/* Dynamic Stage selector */}
      <div className="flex-1 md:flex-initial flex items-center justify-between md:justify-start gap-2 bg-[#E7ECF3] shadow-[3px_3px_6px_#AEB9C9,-3px_-3px_6px_#FFFFFF] rounded-xl px-3.5 py-1.5 h-[42px]">
        <span className="text-xs font-bold text-[#5C6478]">Stage:</span>
        <select 
          onChange={handleStageChange}
          disabled={isPending || !canEdit}
          className={selectClass}
          value={localStage}
        >
          {stages.length > 0 ? (
            stages.map(s => (
              <option key={s.id} value={s.name}>{s.name}</option>
            ))
          ) : (
            LEAD_STAGES.map(stage => (
              <option key={stage} value={stage}>{stage}</option>
            ))
          )}
        </select>
      </div>

      {/* Star rating selector */}
      <div className="flex-1 md:flex-initial flex items-center justify-between md:justify-start gap-2.5 bg-[#E7ECF3] shadow-[3px_3px_6px_#AEB9C9,-3px_-3px_6px_#FFFFFF] rounded-xl px-4 py-1.5 h-[42px]">
        <span className="text-xs font-bold text-[#5C6478]">Rating:</span>
        <StarRating 
          rating={localRating} 
          onChange={handleRatingSelect} 
          editable={canEdit && !isPending} 
          size={16} 
        />
      </div>
    </div>
  )
}

'use client'

import { useState } from 'react'
import { Clock, AlertCircle, CheckSquare, X, Check } from 'lucide-react'
import Link from 'next/link'
import { updateTaskStatus } from '@/app/actions/tasks'

export default function TasksModalClient({ 
  tasks, 
  pendingCount 
}: { 
  tasks: any[]
  pendingCount: number 
}) {
  const [isOpen, setIsOpen] = useState(false)
  const [activeTab, setActiveTab] = useState<'pending' | 'completed'>('pending')
  const [localTasks, setLocalTasks] = useState(tasks)

  const pendingTasks = localTasks.filter(t => t.status === 'Pending')
  const completedTasks = localTasks.filter(t => t.status === 'Completed').sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())

  const handleTaskComplete = async (taskId: string) => {
    // Optimistic UI update
    setLocalTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: 'Completed', updatedAt: new Date().toISOString() } : t))
    try {
      await updateTaskStatus(taskId, 'Completed')
    } catch (err) {
      console.error(err)
    }
  }

  return (
    <>
      {/* Trigger Card */}
      <div 
        onClick={() => setIsOpen(true)}
        className="neo-raised p-6 hover:-translate-y-1.5 transition-all duration-300 cursor-pointer"
      >
        <div className="flex items-center justify-between">
          <h3 className="text-xs font-bold text-[#5C6478]">Pending Tasks</h3>
          <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-[#FF987A] to-[#FF542B] shadow-[3px_3px_6px_#AEB9C9,-3px_3px_6px_#FFFFFF] flex items-center justify-center text-white">
            <Clock className="h-4.5 w-4.5" />
          </div>
        </div>
        <p className="text-3xl font-black text-[#202638] font-display mt-4">{pendingCount}</p>
        <p className="text-[10px] text-[#FF7A52] font-bold mt-2 flex items-center gap-1">
          <AlertCircle className="h-3.5 w-3.5" /> Click to view and manage tasks
        </p>
      </div>

      {/* Modal Overlay */}
      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/30 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="neo-raised-lg w-full max-w-2xl max-h-[80vh] flex flex-col p-8 animate-in zoom-in-95 duration-200">
            
            {/* Header */}
            <div className="flex items-center justify-between pb-5 border-b border-[#AEB9C9]/20">
              <h2 className="text-base font-bold text-[#202638] font-display">Task Management</h2>
              <button 
                onClick={() => setIsOpen(false)}
                className="p-1.5 rounded-xl bg-[#E7ECF3] shadow-[3px_3px_6px_#AEB9C9,-3px_-3px_6px_#FFFFFF] hover:shadow-[inset_2px_2px_4px_#AEB9C9,inset_-2px_-2px_4px_#FFFFFF] text-[#5C6478] transition-all"
                aria-label="Close tasks dialog"
              >
                <X className="h-4.5 w-4.5" />
              </button>
            </div>

            {/* Tab controls */}
            <div className="flex gap-4 my-5 bg-[#E7ECF3] shadow-[inset_2px_2px_5px_#AEB9C9,inset_-2px_-2px_5px_#FFFFFF] p-1.5 rounded-xl">
              <button 
                onClick={() => setActiveTab('pending')}
                className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${
                  activeTab === 'pending'
                    ? 'text-[#202638] bg-[#E7ECF3] shadow-[2px_2px_5px_#AEB9C9,-2px_-2px_5px_#FFFFFF]'
                    : 'text-[#8891A3] hover:text-[#202638]'
                }`}
              >
                Pending ({pendingTasks.length})
              </button>
              <button 
                onClick={() => setActiveTab('completed')}
                className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${
                  activeTab === 'completed'
                    ? 'text-[#202638] bg-[#E7ECF3] shadow-[2px_2px_5px_#AEB9C9,-2px_-2px_5px_#FFFFFF]'
                    : 'text-[#8891A3] hover:text-[#202638]'
                }`}
              >
                History ({completedTasks.length})
              </button>
            </div>

            {/* Task list container */}
            <div className="overflow-y-auto flex-1 space-y-4 pr-1">
              {activeTab === 'pending' && (
                <div className="space-y-4">
                  {pendingTasks.length === 0 ? (
                    <p className="text-[#8891A3] text-xs font-bold text-center py-8">No pending tasks!</p>
                  ) : (
                    pendingTasks.map(task => (
                      <div key={task.id} className="bg-[#E7ECF3] p-4 rounded-xl shadow-[inset_2px_2px_4px_#AEB9C9,inset_-2px_-2px_4px_#FFFFFF] flex items-start gap-3 transition-all">
                        <input 
                          type="checkbox" 
                          onChange={() => handleTaskComplete(task.id)}
                          className="mt-1 w-4 h-4 rounded cursor-pointer accent-[#4855E4] shrink-0" 
                        />
                        <div className="flex-1 min-w-0">
                          <p className="text-xs font-bold text-[#202638] leading-normal">
                            {task.leadId ? (
                              <Link href={`/dashboard/leads/${task.leadId}`} onClick={() => setIsOpen(false)} className="hover:text-[#4855E4] hover:underline font-bold">
                                {task.description}
                              </Link>
                            ) : (
                              <span>{task.description}</span>
                            )}
                          </p>
                          <p className="text-[10px] text-[#FF7A52] font-bold mt-1.5 flex items-center gap-1">
                            <Clock className="h-3.5 w-3.5" /> Due: {new Date(task.dueDate).toLocaleString()}{task.lead ? ` - ${task.lead.fullName}` : ''}
                          </p>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              )}
 
              {activeTab === 'completed' && (
                <div className="space-y-4">
                  {completedTasks.length === 0 ? (
                    <p className="text-[#8891A3] text-xs font-bold text-center py-8">No task history yet.</p>
                  ) : (
                    completedTasks.map(task => (
                      <div key={task.id} className="bg-[#E7ECF3] p-4 rounded-xl shadow-[4px_4px_8px_#AEB9C9,-4px_-4px_8px_#FFFFFF] flex items-start gap-3 opacity-80">
                        <Check className="mt-0.5 h-4.5 w-4.5 text-[#21C285] shrink-0" />
                        <div className="flex-1 min-w-0">
                          <p className="text-xs font-bold text-[#8891A3] line-through leading-normal">
                            {task.leadId ? (
                              <Link href={`/dashboard/leads/${task.leadId}`} onClick={() => setIsOpen(false)} className="hover:text-[#21C285] hover:underline">
                                {task.description}
                              </Link>
                            ) : (
                              <span>{task.description}</span>
                            )}
                          </p>
                          <p className="text-[10px] text-[#8891A3] font-semibold mt-1">
                            Completed: {new Date(task.updatedAt).toLocaleString()}{task.lead ? ` - ${task.lead.fullName}` : ''}
                          </p>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </>
  )
}

'use client'

import { useState } from 'react'
import { transferLead } from '@/app/actions/leads'
import { ArrowRightLeft } from 'lucide-react'

export default function TransferLeadButton({ leadId, currentCounselorId, counselors }: { leadId: string, currentCounselorId: string, counselors: any[] }) {
  const [isOpen, setIsOpen] = useState(false)
  const [selectedId, setSelectedId] = useState(currentCounselorId)
  const [isTransferring, setIsTransferring] = useState(false)

  const handleTransfer = async () => {
    if (!selectedId || selectedId === currentCounselorId) {
      setIsOpen(false)
      return
    }
    
    setIsTransferring(true)
    await transferLead(leadId, selectedId)
    setIsTransferring(false)
    setIsOpen(false)
  }

  return (
    <div className="relative">
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="flex items-center space-x-2 bg-neutral-800 hover:bg-neutral-700 text-white px-3 py-1.5 rounded-lg text-sm font-medium transition-colors"
      >
        <ArrowRightLeft className="h-4 w-4 text-blue-400" />
        <span>Transfer</span>
      </button>

      {isOpen && (
        <div className="absolute left-0 md:left-auto md:right-0 mt-2 w-64 bg-neutral-900 border border-neutral-800 rounded-xl shadow-2xl p-4 z-50">
          <h4 className="text-sm font-medium text-white mb-3">Transfer to Counselor</h4>
          <select 
            value={selectedId}
            onChange={(e) => setSelectedId(e.target.value)}
            className="w-full bg-neutral-950 border border-neutral-700 rounded-lg p-2 text-sm text-white mb-3 focus:ring-1 focus:ring-blue-500"
          >
            <option value="">Select Counselor</option>
            {counselors.map(c => (
              <option key={c.id} value={c.id}>{c.fullName}</option>
            ))}
          </select>
          <div className="flex justify-end space-x-2">
            <button onClick={() => setIsOpen(false)} className="px-3 py-1.5 text-xs text-neutral-400 hover:text-white">Cancel</button>
            <button 
              onClick={handleTransfer} 
              disabled={isTransferring || !selectedId || selectedId === currentCounselorId}
              className="bg-blue-600 hover:bg-blue-700 text-white px-3 py-1.5 rounded-lg text-xs font-medium disabled:opacity-50"
            >
              {isTransferring ? 'Saving...' : 'Confirm'}
            </button>
          </div>
        </div>
      )}
    </div>
  )
}

import { createServerClient } from '@supabase/ssr'
import { NextResponse, type NextRequest } from 'next/server'

export async function updateSession(request: NextRequest) {
  let supabaseResponse = NextResponse.next({
    request,
  })

  const supabase = createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return request.cookies.getAll()
        },
        setAll(cookiesToSet) {
          cookiesToSet.forEach(({ name, value, options }) => request.cookies.set(name, value))
          supabaseResponse = NextResponse.next({
            request,
          })
          cookiesToSet.forEach(({ name, value, options }) =>
            supabaseResponse.cookies.set(name, value, options)
          )
        },
      },
    }
  )

  // IMPORTANT: Avoid writing any logic between createServerClient and
  // supabase.auth.getUser(). A simple mistake could make it very hard to debug
  // issues with users being randomly logged out.
  const {
    data: { user },
  } = await supabase.auth.getUser()

  const isLoginPage = request.nextUrl.pathname.startsWith('/login')
  const isDashboardPage = request.nextUrl.pathname.startsWith('/dashboard')

  if (!user && isDashboardPage) {
    // no user, potentially respond by redirecting the user to the login page
    const url = request.nextUrl.clone()
    url.pathname = '/login'
    return NextResponse.redirect(url)
  }

  if (user && isLoginPage) {
    // Only query database when visiting the login page with an active auth session
    const { data: dbUser } = await supabase
      .from('User')
      .select('id')
      .eq('email', user.email)
      .maybeSingle()

    if (dbUser) {
      const url = request.nextUrl.clone()
      url.pathname = '/dashboard'
      return NextResponse.redirect(url)
    } else {
      // Logged in via Supabase Auth but no DB profile exists. Force sign-out to clean the session.
      await supabase.auth.signOut()
    }
  }

  // IMPORTANT: You *must* return the supabaseResponse object as it is.
  // If you're creating a new response object with NextResponse.next() make sure to:
  // 1. Pass the request in it, like so:
  //    const myNewResponse = NextResponse.next({ request })
  // 2. Copy over the cookies, like so:
  //    myNewResponse.cookies.setAll(supabaseResponse.cookies.getAll())
  // 3. Change the myNewResponse object to fit your needs, but avoid changing
  //    the cookies!
  // 4. Finally:
  //    return myNewResponse
  // If this is not done, you may be causing the browser and server to go out
  // of sync and terminate the user's session prematurely!
  return supabaseResponse
}

import { createServerClient, type CookieOptions } from '@supabase/ssr'
import { cookies } from 'next/headers'

export async function createClient() {
  const cookieStore = await cookies()

  return createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return cookieStore.getAll()
        },
        setAll(cookiesToSet) {
          try {
            cookiesToSet.forEach(({ name, value, options }) =>
              cookieStore.set(name, value, options)
            )
          } catch {
            // The `setAll` method was called from a Server Component.
            // This can be ignored if you have middleware refreshing
            // user sessions.
          }
        },
      },
    }
  )
}
